import{c as a,Q as n,j as e,m as i}from"./chunks/framework.D9IbVcwA.js";const b=JSON.parse('{"title":"IF 标志丢失","description":"","frontmatter":{"title":"IF 标志丢失"},"headers":[],"relativePath":"notes/020/002_if_flag_lost_in_context_switch.md","filePath":"notes/020/002_if_flag_lost_in_context_switch.md","lastUpdated":1779686691000}'),t={name:"notes/020/002_if_flag_lost_in_context_switch.md"};function p(l,s,r,c,o,d){return n(),e("div",null,[...s[0]||(s[0]=[i(`<h1 id="_020-·-context-switch-丢失-if-标志导致后续线程中断全关" tabindex="-1">020 · context_switch 丢失 IF 标志导致后续线程中断全关 <a class="header-anchor" href="#_020-·-context-switch-丢失-if-标志导致后续线程中断全关" aria-label="Permalink to &quot;020 · context_switch 丢失 IF 标志导致后续线程中断全关&quot;">​</a></h1><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p>6 个线程 × 10 次迭代 × 20M 忙循环。第一次抢占成功（A 跑了 2 次后切到 B），但之后 B/C/D/E/F 全部顺序跑完，再也没有被抢占：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[A] tid=2 iter 1/10</span></span>
<span class="line"><span>[A] tid=2 iter 2/10          ← 第一次抢占发生在这里</span></span>
<span class="line"><span>[B] tid=3 iter 1/10</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[B] tid=3 iter 10/10         ← B 跑完，从未被抢占</span></span>
<span class="line"><span>[B] done</span></span>
<span class="line"><span>[C] tid=4 iter 1/10</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[F] done</span></span>
<span class="line"><span>[A] tid=2 iter 3/10          ← A 回来继续</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>[A] done</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="根因" tabindex="-1">根因 <a class="header-anchor" href="#根因" aria-label="Permalink to &quot;根因&quot;">​</a></h2><p><code>context_switch.S</code> 只保存/恢复 callee-saved 寄存器（r15-r12, rbp, rbx, rsp, rip），<strong>不涉及 RFLAGS</strong>。</p><p>抢占发生时的调用链：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IRQ0 → ISR stub (CPU 清除 IF) → pit_irq0_handler → Scheduler::tick() → schedule() → context_switch</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>进入 ISR 时，CPU 自动将 IF 清零（interrupt gate 语义）。<code>context_switch</code> 切换到新任务时，新任务<strong>继承了当前 IF=0</strong>。</p><ul><li><strong>新任务（首次运行）</strong>：<code>ctx.rip</code> 指向入口函数，<code>jmp *56(%rsi)</code> 直接跳转，IF 仍为 0 → 永远收不到定时器中断</li><li><strong>被抢占过的任务（恢复运行）</strong>：<code>ctx.rip</code> 指向 <code>.restore</code>，恢复后通过 <code>ret</code> 链回到 ISR stub → <code>IRETQ</code> 从中断帧还原原始 RFLAGS（IF=1） → 中断恢复</li></ul><p>所以只有第一个被抢占的任务（A）能恢复中断，后续所有新启动的线程（B-F）都带着 IF=0 运行。</p><h2 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h2><p>在 <code>context_switch.S</code> 中，切换栈之后、跳转到新任务之前加一条 <code>sti</code>：</p><div class="language-asm vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    movq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 48</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsp</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 切换到新任务栈</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    sti</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                           # 开中断</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    jmp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> *</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">56</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">rsi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)                </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 跳转到新任务</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>为什么安全：</p><ul><li><strong>新任务</strong>：以 IF=1 启动，定时器中断正常到达 → 抢占正常</li><li><strong>被抢占的任务</strong>：恢复到 <code>.restore</code> → <code>ret</code> 链回到 ISR → <code>IRETQ</code> 还原原始 RFLAGS，<code>sti</code> 是无害冗余</li><li><strong>嵌套中断风险</strong>：从 <code>.restore</code> 到 <code>IRETQ</code> 的退栈路径极短（微秒级），100Hz 定时器（10ms 间隔）在此窗口命中的概率可忽略</li></ul><h2 id="教训" tabindex="-1">教训 <a class="header-anchor" href="#教训" aria-label="Permalink to &quot;教训&quot;">​</a></h2><p>协作式 context_switch 设计时不考虑 RFLAGS 是合理的——总是在明确的调用点切换，IF 不变。但一旦从中断上下文调用同一个 <code>context_switch</code>，就必须保证新任务的中断状态正确。这是从 cooperative 迈向 preemptive 的经典陷阱。</p><p>一种更精细的方案是把 RFLAGS 加入 <code>CpuContext</code> 并在保存/恢复时使用 <code>pushfq/popfq</code>，但对当前仅内核线程的场景来说，在切换点 <code>sti</code> 是最简洁的修复。</p>`,19)])])}const u=a(t,[["render",p]]);export{b as __pageData,u as default};
